def make_schedule(name: str = "cosine", T: int = 1000, **kwargs) -> dict:
    """
    Factory for noise schedules. Returns unified dict with keys:
      betas, alphas, alpha_bars, snr, sqrt_alpha_bar, sqrt_one_minus_alpha_bar
    """
    if name == "linear":
        return linear_schedule(
            T,
            beta_start=kwargs.get("beta_start", 1e-4),
            beta_end=kwargs.get("beta_end", 0.02),
        )
    elif name == "cosine":
        return cosine_schedule(T, s=kwargs.get("s", 0.008))
    elif name == "sigmoid":
        # Sigmoid schedule: interpolates between linear and cosine
        start  = kwargs.get("start", -3)
        end    = kwargs.get("end",    3)
        tau    = kwargs.get("tau",    1.0)
        t      = torch.linspace(0, 1, T + 1, dtype=torch.float64)
        v_start = torch.sigmoid(torch.tensor(start / tau))
        v_end   = torch.sigmoid(torch.tensor(end / tau))
        # ᾱ_t decreases from ≈1 to ≈0 following sigmoid
        alpha_bars = (torch.sigmoid((start + (end - start) * t) / tau) - v_start) / (v_end - v_start)
        alpha_bars = (1 - alpha_bars)[1:]   # flip so high t → low ᾱ, skip t=0
        alpha_bars_prev = torch.cat([torch.ones(1, dtype=torch.float64), alpha_bars[:-1]])
        betas   = (1 - alpha_bars / alpha_bars_prev).clamp(max=0.999)
        alphas  = 1 - betas
        snr     = alpha_bars / (1 - alpha_bars)
        return {
            "betas": betas, "alphas": alphas, "alpha_bars": alpha_bars, "snr": snr,
            "sqrt_alpha_bar": alpha_bars.sqrt(),
            "sqrt_one_minus_alpha_bar": (1 - alpha_bars).sqrt(),
        }
    else:
        raise ValueError(f"Unknown schedule: {name}")
